import{bQ as a,aL as e,u as d,G as s}from"./chunks/framework.D06dwy5q.js";const u=JSON.parse('{"title":"指标体系","description":"","frontmatter":{},"headers":[],"relativePath":"12.可观测性与监控告警/02-指标体系.md","filePath":"12.可观测性与监控告警/02-指标体系.md","lastUpdated":null}'),o={name:"12.可观测性与监控告警/02-指标体系.md"};function n(r,t,p,i,l,c){return e(),d("div",null,[...t[0]||(t[0]=[s(`<h1 id="指标体系" tabindex="-1">指标体系 <a class="header-anchor" href="#指标体系" aria-label="Permalink to &quot;指标体系&quot;">​</a></h1><p>指标是 Prometheus 体系里最基本的数据单元。在配置 Exporter 和写 PromQL 之前，先理清指标本身的结构——指标名、标签、类型和命名习惯。</p><h2 id="一个指标长什么样" tabindex="-1">一个指标长什么样 <a class="header-anchor" href="#一个指标长什么样" aria-label="Permalink to &quot;一个指标长什么样&quot;">​</a></h2><p>在 Prometheus 里，一条指标数据（称为&quot;样本&quot;）由四个要素组成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>node_memory_MemAvailable_bytes{instance=&quot;192.168.10.11:9100&quot;, job=&quot;node&quot;} 6011232256</span></span></code></pre></div><p>拆开看：</p><table tabindex="0"><thead><tr><th>部分</th><th>值</th><th>含义</th></tr></thead><tbody><tr><td>指标名</td><td><code>node_memory_MemAvailable_bytes</code></td><td>这行数据测量的是&quot;Linux 可用内存字节数&quot;</td></tr><tr><td>标签</td><td><code>instance=&quot;192.168.10.11:9100&quot;</code></td><td>来自哪台机器</td></tr><tr><td>标签</td><td><code>job=&quot;node&quot;</code></td><td>属于哪组采集任务</td></tr><tr><td>值</td><td><code>6011232256</code></td><td>当前可用大约 6GB</td></tr></tbody></table><p>同一个指标名加上同一组标签，就是一条&quot;时间序列&quot;——时间轴上每过一个采集间隔会增加一个新样本点。标签里任何一个值变了，就变成另一条序列。比如 <code>instance=&quot;192.168.10.11:9100&quot;</code> 和 <code>instance=&quot;192.168.10.12:9100&quot;</code> 是两条不同的序列，因为 instance 不同了。Graph 视图里两条序列各自一条线，Table 视图里两条序列各自一行。</p><h2 id="标签和基数" tabindex="-1">标签和基数 <a class="header-anchor" href="#标签和基数" aria-label="Permalink to &quot;标签和基数&quot;">​</a></h2><p>标签是 Prometheus 设计里很关键的一环。标签可以按不同维度过滤和聚合：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 只看 node job 的</span></span>
<span class="line"><span>up{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 加起来看 node job 一共几个目标</span></span>
<span class="line"><span>sum(up{job=&quot;node&quot;})</span></span></code></pre></div><p>但不是所有信息都适合放进标签。标签每多一种取值组合，就多出一条时间序列。如果把用户 ID 放进标签，几万个用户就是几万条序列，Prometheus 的内存、磁盘和查询性能都会被撑爆——这个叫标签基数爆炸。</p><p>一个简单的判断方法：这个字段有多少种可能的取值。</p><table tabindex="0"><thead><tr><th>适合作为标签</th><th>不适合作为标签</th></tr></thead><tbody><tr><td>环境（env：prod/staging/dev）—— 3 种取值</td><td>用户 ID —— 几万到几百万种取值</td></tr><tr><td>服务名（service）—— 几十种取值</td><td>请求 ID —— 每次请求都不同</td></tr><tr><td>实例（instance）—— 几十到几百个</td><td>订单号 —— 和用户 ID 类似，增长很快</td></tr><tr><td>状态码（status：200/404/500）—— 不到 10 种</td><td>错误堆栈 —— 每次异常内容都不一样</td></tr></tbody></table><p>请求 ID 和错误堆栈适合放在日志和链路追踪里。指标上需要关联到某次请求时，可以用 exemplar（在指标数据上附带一个 trace_id），而不是把 trace_id 变成指标标签。</p><h2 id="四种指标类型" tabindex="-1">四种指标类型 <a class="header-anchor" href="#四种指标类型" aria-label="Permalink to &quot;四种指标类型&quot;">​</a></h2><p>Prometheus 把指标分为四种类型。区分它们的关键是每种类型用什么函数、能不能直接看当前值。</p><h3 id="counter-计数器-只增不减" tabindex="-1">Counter：计数器，只增不减 <a class="header-anchor" href="#counter-计数器-只增不减" aria-label="Permalink to &quot;Counter：计数器，只增不减&quot;">​</a></h3><p>Counter 记录&quot;到目前为止一共多少次&quot;。请求总数、错误总数、网卡累计接收字节数、CPU 累计运行秒数——这些都是 Counter。</p><p>Counter 有两个特点：只增不减（重启后会归零）；绝对值本身意义不大——&quot;网卡一共收了 15TB&quot;不说明当前是否在跑满带宽。所以 Counter 通常不直接看当前值，而是算它的增长速率：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 看最近 5 分钟每秒增长多少——这就是 Mbps</span></span>
<span class="line"><span>rate(node_network_receive_bytes_total{job=&quot;node&quot;}[5m])</span></span></code></pre></div><p><code>[5m]</code> 的意思是&quot;取最近 5 分钟的所有样本点&quot;，<code>rate()</code> 根据这些样本点的增长来算平均每秒速率。因为 Counter 会因进程重启重新从 0 开始计数（术语叫&quot;reset&quot;），<code>rate()</code> 内部会自动处理这种归零——它看到当前值比上一个值小，就知道发生了一次重置，会按实际增量来算而不是直接相减。</p><h3 id="gauge-仪表盘-可增可减" tabindex="-1">Gauge：仪表盘，可增可减 <a class="header-anchor" href="#gauge-仪表盘-可增可减" aria-label="Permalink to &quot;Gauge：仪表盘，可增可减&quot;">​</a></h3><p>Gauge 是&quot;当前是多少&quot;，和温度计一样，可以升可以降。当前内存用量、当前连接数、当前队列长度、磁盘可用空间——这些都是 Gauge。</p><p>Gauge 通常可以直接查当前值，也可以算平均值、最大值：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 直接看当前可用内存</span></span>
<span class="line"><span>node_memory_MemAvailable_bytes{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 看所有机器的平均 CPU 使用率</span></span>
<span class="line"><span>avg(node_cpu_usage_percent)</span></span></code></pre></div><p>Gauge 没有&quot;归零&quot;的问题，它本来就随时在变。</p><h3 id="histogram-直方图-统计分布" tabindex="-1">Histogram：直方图，统计分布 <a class="header-anchor" href="#histogram-直方图-统计分布" aria-label="Permalink to &quot;Histogram：直方图，统计分布&quot;">​</a></h3><p>Histogram 用多个&quot;桶&quot;（bucket）来记录数据分布。比如 HTTP 请求耗时，不是只记一个平均值，而是统计：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>耗时 ≤ 0.1s  有几个请求</span></span>
<span class="line"><span>耗时 ≤ 0.5s  有几个请求</span></span>
<span class="line"><span>耗时 ≤ 1s    有几个请求</span></span>
<span class="line"><span>耗时 ≤ 2s    有几个请求</span></span>
<span class="line"><span>耗时 ≤ 10s   有几个请求</span></span>
<span class="line"><span>...直到 Infinity（兜底桶）</span></span></code></pre></div><p>从这些桶里可以算出 P50、P90、P95、P99——比平均值有用得多。平均值 200ms 可能是&quot;大部分请求 50ms，偶尔几个请求 5 秒&quot;的结果，平均值把问题抹平了。</p><p>Histogram 每个桶本身也是一个 Counter（只增不减），所以也需要用 <code>rate()</code> 来算增长。从 Histogram 算 P95 的典型写法：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>histogram_quantile(0.95, rate(http_request_duration_seconds_bucket[5m]))</span></span></code></pre></div><h3 id="summary-在客户端侧算好的分位数" tabindex="-1">Summary：在客户端侧算好的分位数 <a class="header-anchor" href="#summary-在客户端侧算好的分位数" aria-label="Permalink to &quot;Summary：在客户端侧算好的分位数&quot;">​</a></h3><p>Summary 也在记录分位数，但分位数在客户端侧（被监控的应用自己）算好，直接暴露出来。P95 延迟用 Summary 时直接就是一个指标值。缺点也很明显——两台机器的 Summary 没法重新聚合：两台机器的 P95 取平均不代表整体的 P95。Histogram 没有这个问题，因为桶数据可以跨实例加和再算分位。</p><p>Prometheus 生态里 Histogram 用得更多，新接入的指标也优先选 Histogram。</p><table tabindex="0"><thead><tr><th>类型</th><th>特点</th><th>例子</th><th>通常怎么用</th></tr></thead><tbody><tr><td>Counter</td><td>只增不减，重启归零</td><td>请求总数、错误数、网卡字节累计</td><td><code>rate()</code>、<code>increase()</code> 算变化速率</td></tr><tr><td>Gauge</td><td>可增可减</td><td>当前内存、连接数、磁盘可用</td><td>直接查当前值，或 avg/max</td></tr><tr><td>Histogram</td><td>分桶记录分布</td><td>HTTP 耗时、RPC 延迟</td><td><code>histogram_quantile()</code> 算分位</td></tr><tr><td>Summary</td><td>客户端侧分位</td><td>部分 SDK 暴露的分位值</td><td>直接看，但跨实例无法聚合</td></tr></tbody></table><h2 id="red-和-use-两个选指标的角度" tabindex="-1">RED 和 USE：两个选指标的角度 <a class="header-anchor" href="#red-和-use-两个选指标的角度" aria-label="Permalink to &quot;RED 和 USE：两个选指标的角度&quot;">​</a></h2><p>接入一个新服务时，可以从两个角度来想关注什么指标。</p><p>服务对外提供的接口，看 RED：</p><table tabindex="0"><thead><tr><th>维度</th><th>含义</th><th>例子</th></tr></thead><tbody><tr><td>Rate</td><td>每秒请求数</td><td>QPS 曲线是平稳、突增还是骤降</td></tr><tr><td>Errors</td><td>错误率</td><td>5xx 比例、业务失败比例</td></tr><tr><td>Duration</td><td>耗时分布</td><td>P95/P99 有没有变长</td></tr></tbody></table><p>机器自身的资源，看 USE：</p><table tabindex="0"><thead><tr><th>维度</th><th>含义</th><th>例子</th></tr></thead><tbody><tr><td>Utilization</td><td>使用率</td><td>CPU 使用率、磁盘使用率、内存使用率</td></tr><tr><td>Saturation</td><td>饱和度（排队）</td><td>CPU load、队列长度、等待中的请求数</td></tr><tr><td>Errors</td><td>错误</td><td>磁盘读写错误、网卡丢包、TCP 重传</td></tr></tbody></table><p>RED 回答&quot;服务是不是在好好干活&quot;，USE 回答&quot;机器是不是还能撑住&quot;。比如接口 P99 从 200ms 涨到 3s，但请求量没有明显增加，错误率也没涨，先看 USE 里的 CPU、磁盘 IO 和连接数；如果同一时间 5xx 也上涨，应用日志出现下游超时，问题更像服务链路或依赖异常。RED 先定影响范围，USE 再确认机器和资源有没有顶住。</p><h2 id="采集间隔和保留周期" tabindex="-1">采集间隔和保留周期 <a class="header-anchor" href="#采集间隔和保留周期" aria-label="Permalink to &quot;采集间隔和保留周期&quot;">​</a></h2><p>采集间隔决定指标的精细程度。间隔越短，尖刺越不会被抹平——一个持续 10 秒的 CPU 高峰用 15 秒间隔抓取能抓到，用 5 分钟间隔可能就漏了。但间隔越短，存储压力越大。</p><table tabindex="0"><thead><tr><th>场景</th><th>常见间隔</th><th>说明</th></tr></thead><tbody><tr><td>主机基础指标</td><td><code>15s</code> 或 <code>30s</code></td><td>资源瓶颈通常不会在几秒内出现又消失</td></tr><tr><td>业务接口指标</td><td><code>15s</code> 或 <code>30s</code></td><td>和主机保持一致便于对比</td></tr><tr><td>低频批任务</td><td><code>1m</code></td><td>本身就几分钟才跑一次</td></tr><tr><td>黑盒拨测</td><td>按接口重要性</td><td>核心接口可能 10s，低频接口 1min</td></tr></tbody></table><p>保留周期决定能回看多久。实验环境 7~15 天就够了。生产环境如果想回看更久（比如做月度报表、年度容量规划），只靠本地 Prometheus 保存几个月会很占磁盘和查询性能——更常见的做法是 Prometheus 本地保留短期的（几天到几周），远期数据交给 VictoriaMetrics、Thanos、Mimir 这类远端存储。</p><h2 id="指标命名习惯" tabindex="-1">指标命名习惯 <a class="header-anchor" href="#指标命名习惯" aria-label="Permalink to &quot;指标命名习惯&quot;">​</a></h2><p>Prometheus 生态里指标名有固定习惯：</p><table tabindex="0"><thead><tr><th>命名规则</th><th>例子</th></tr></thead><tbody><tr><td>单位和含义写进名字里</td><td><code>node_memory_MemAvailable_bytes</code>（bytes）</td></tr><tr><td>Counter 类以 <code>_total</code> 结尾</td><td><code>http_requests_total</code></td></tr><tr><td>Histogram 桶以 <code>_bucket</code> 结尾</td><td><code>http_request_duration_seconds_bucket</code></td></tr><tr><td><code>_seconds</code> 表示时间</td><td><code>scrape_duration_seconds</code></td></tr></tbody></table><p>单位写进指标名能让 Grafana 面板自动识别合适的单位格式，也能避免同一条曲线里混着 s 和 ms 导致误读数值。</p><h2 id="从指标到告警" tabindex="-1">从指标到告警 <a class="header-anchor" href="#从指标到告警" aria-label="Permalink to &quot;从指标到告警&quot;">​</a></h2><p>不是所有指标都要变成告警。指标可以有一大堆——排查和观察时需要越丰富越好。告警要往回收——只触发需要人介入的情况。</p><p>判断一条告警值不值得设，可以问三个问题：异常能不能被指标稳定表达（还是偶尔出现一次就没了）、持续一段时间会不会恶化（还是自动恢复）、需要有人处理吗（还是系统会自动处理）。三条都满足，告警更有可能有用。缺一条，这条告警就可能变成群聊里的噪声。</p>`,55)])])}const b=a(o,[["render",n]]);export{u as __pageData,b as default};
